import { KEYS, createSlatePlugin, createTSlatePlugin, getInjectMatch } from "platejs";

//#region src/lib/BaseFontBackgroundColorPlugin.ts
const BaseFontBackgroundColorPlugin = createSlatePlugin({
	key: KEYS.backgroundColor,
	inject: { nodeProps: { nodeKey: "backgroundColor" } },
	parsers: { html: { deserializer: {
		isLeaf: true,
		rules: [{ validStyle: { backgroundColor: "*" } }],
		parse: ({ element, type }) => ({ [type]: element.style.backgroundColor })
	} } }
}).extendTransforms(({ editor }) => ({ addMark: (value) => {
	editor.tf.addMarks({ [KEYS.backgroundColor]: value });
} }));

//#endregion
//#region src/lib/BaseFontColorPlugin.ts
const BaseFontColorPlugin = createSlatePlugin({
	key: KEYS.color,
	inject: { nodeProps: {
		defaultNodeValue: "black",
		nodeKey: "color"
	} },
	parsers: { html: { deserializer: {
		isLeaf: true,
		rules: [{ validStyle: { color: "*" } }],
		parse({ element, type }) {
			if (element.style.color) return { [type]: element.style.color };
		}
	} } }
}).extendTransforms(({ editor }) => ({ addMark: (value) => {
	editor.tf.addMarks({ [KEYS.color]: value });
} }));

